-- MES 基础数据测试脚本
-- 依据用户提供的 18 张表生成，适用于 MySQL 8.x
-- 每张表不少于 30 条；mes_material 90 条，mes_bom_detail 90 条，mes_route_detail 90 条
-- 建议在空表或独立测试库中执行。脚本显式写入主键，以保证关联关系稳定。

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;
START TRANSACTION;



















COMMIT;
SET FOREIGN_KEY_CHECKS = 1;

-- 导入后可执行以下语句核验每张表的数据量

SELECT 'mes_factory' AS table_name, COUNT(*) AS row_count FROM mes_factory;

SELECT 'mes_workshop' AS table_name, COUNT(*) AS row_count FROM mes_workshop;

SELECT 'mes_production_line' AS table_name, COUNT(*) AS row_count FROM mes_production_line;

SELECT 'mes_work_center' AS table_name, COUNT(*) AS row_count FROM mes_work_center;

SELECT 'mes_workstation' AS table_name, COUNT(*) AS row_count FROM mes_workstation;

SELECT 'mes_team' AS table_name, COUNT(*) AS row_count FROM mes_team;

SELECT 'mes_shift' AS table_name, COUNT(*) AS row_count FROM mes_shift;

SELECT 'mes_equipment' AS table_name, COUNT(*) AS row_count FROM mes_equipment;

SELECT 'mes_unit' AS table_name, COUNT(*) AS row_count FROM mes_unit;

SELECT 'mes_material' AS table_name, COUNT(*) AS row_count FROM mes_material;

SELECT 'mes_process' AS table_name, COUNT(*) AS row_count FROM mes_process;

SELECT 'mes_bom' AS table_name, COUNT(*) AS row_count FROM mes_bom;

SELECT 'mes_bom_detail' AS table_name, COUNT(*) AS row_count FROM mes_bom_detail;

SELECT 'mes_route' AS table_name, COUNT(*) AS row_count FROM mes_route;

SELECT 'mes_route_detail' AS table_name, COUNT(*) AS row_count FROM mes_route_detail;

SELECT 'mes_defect_type' AS table_name, COUNT(*) AS row_count FROM mes_defect_type;

SELECT 'mes_exception_type' AS table_name, COUNT(*) AS row_count FROM mes_exception_type;

SELECT 'mes_downtime_reason' AS table_name, COUNT(*) AS row_count FROM mes_downtime_reason;
